async (params, browser) => {
  // Open TV show page
  await browser.open(`${params.show_url}`)

  // Wait for show page to load
  await browser.waitForSelector('h1, [data-qa=\'score-panel\'], [class*=\'scoreboard\'], rt-button', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract TV show details
  const tvshow_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [class*="scoreboard"] h1'); const tomatometerEl = document.querySelector('rt-button[slot="criticsScore"] rt-text, [data-qa="tomatometer"]'); const audienceEl = document.querySelector('rt-button[slot="audienceScore"] rt-text, [data-qa="audience-score"]'); const consensusEl = document.querySelector('[data-qa="critics-consensus"], [class*="consensus"], p[data-qa="what-to-know"]'); const synopsisEl = document.querySelector('[data-qa="series-info-synopsis"], [class*="synopsis"], [data-qa="section:media-scorecard"] p'); const imgEl = document.querySelector('[data-qa="poster-image"] img, .posterImage img'); const infoEls = document.querySelectorAll('[data-qa="series-info-item"], li[class*="info-item"], [class*="category-wrap"]'); const info = {}; infoEls.forEach(function(el) { const labelEl = el.querySelector('[data-qa="series-info-item-label"], b, [class*="label"]'); const valueEl = el.querySelector('[data-qa="series-info-item-value"], span, [class*="value"]'); if (labelEl && valueEl) { info[labelEl.textContent.trim().replace(':', '')] = valueEl.textContent.trim(); } }); const seasonEls = document.querySelectorAll('[data-qa="season-item"], a[href*="/s"], [class*="season"] a'); const seasons = []; seasonEls.forEach(function(el) { const text = el.textContent.trim(); if (text && text.length < 50) seasons.push(text); }); const castEls = document.querySelectorAll('[data-qa="cast-item"], [class*="cast-item"] a'); const cast = []; castEls.forEach(function(el, idx) { if (idx < 10) { const nameEl = el.querySelector('[data-qa="cast-item-name"], [class*="name"]'); const charEl = el.querySelector('[data-qa="cast-item-character"], [class*="character"]'); cast.push({ name: nameEl ? nameEl.textContent.trim() : el.textContent.trim(), character: charEl ? charEl.textContent.trim() : '' }); } }); return { title: titleEl ? titleEl.textContent.trim() : '', tomatometer: tomatometerEl ? tomatometerEl.textContent.trim() : '', audience_score: audienceEl ? audienceEl.textContent.trim() : '', critics_consensus: consensusEl ? consensusEl.textContent.trim().substring(0, 500) : '', synopsis: synopsisEl ? synopsisEl.textContent.trim().substring(0, 1000) : '', info: info, seasons: seasons.slice(0, 20), cast: cast, image: imgEl ? imgEl.getAttribute('src') : '', url: window.location.href }`)

  return tvshow_data
}
